input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type=json -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/initContainers",
    "value": [
      {
        "name": "install-s3-plugin",
        "image": "docker.elastic.co/elasticsearch/elasticsearch:7.17.9",
        "command": ["/bin/bash", "-c"],
        "args": ["bin/elasticsearch-plugin install --batch repository-s3 2>&1 && echo plugin installed"],
        "volumeMounts": [
          {
            "name": "plugins-volume",
            "mountPath": "/usr/share/elasticsearch/plugins"
          }
        ]
      },
      {
        "name": "configure-keystore",
        "image": "docker.elastic.co/elasticsearch/elasticsearch:7.17.9",
        "command": ["/bin/bash", "-c"],
        "args": [
          "bin/elasticsearch-keystore create && echo -n \"$ACCESS_KEY\" | bin/elasticsearch-keystore add --stdin s3.client.default.access_key && echo -n \"$SECRET_KEY\" | bin/elasticsearch-keystore add --stdin s3.client.default.secret_key && cp /usr/share/elasticsearch/config/elasticsearch.keystore /keystore/elasticsearch.keystore && echo keystore configured"
        ],
        "env": [
          {
            "name": "ACCESS_KEY",
            "valueFrom": {
              "secretKeyRef": {
                "name": "es-secure-settings",
                "key": "s3.client.default.access_key"
              }
            }
          },
          {
            "name": "SECRET_KEY",
            "valueFrom": {
              "secretKeyRef": {
                "name": "es-secure-settings",
                "key": "s3.client.default.secret_key"
              }
            }
          }
        ],
        "volumeMounts": [
          {
            "name": "keystore-volume",
            "mountPath": "/keystore"
          }
        ]
      }
    ]
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "plugins-volume",
      "emptyDir": {}
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "keystore-volume",
      "emptyDir": {}
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "plugins-volume",
      "mountPath": "/usr/share/elasticsearch/plugins"
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "keystore-volume",
      "mountPath": "/usr/share/elasticsearch/config/elasticsearch.keystore",
      "subPath": "elasticsearch.keystore"
    }
  }
]' 2>&1
